final:
module RefModule(A, B, Z, OVF);input [1:0] A;
input [1:0] B;
output reg [1:0] Z; // Change output Z to reg type
output OVF;

wire [2:0] obf_sum;
assign obf_sum = A + B;
assign OVF = (obf_sum > 3);

always @* begin
    if (obf_sum > 3)
        Z = 2'b11;
    else
        Z = obf_sum[1:0];
end

endmodule
